import { test, expect } from '@playwright/test';

test('Amazon SG - Search phone and sort by Price: Low to High', async ({ page }) => {
  // 1. Launch browser → Amazon SG.
  await page.goto('https://www.amazon.sg/');

  // 2. Search for "phone".
  const searchBox = page.locator('input#twotabsearchtextbox');
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('phone');
  await page.getByRole('button', { name: 'Go' }).click();

  // 3. Select "Price: Low to High" sort option.
  const sortDropdown = page.locator('select#s-result-sort-select');
  await expect(sortDropdown).toBeVisible({ timeout: 10000 });
  await sortDropdown.selectOption({ label: 'Price: Low to High' });

  // 4. Wait for results refresh.
  // Wait for network idle or for the results to update
  await page.waitForLoadState('networkidle');
  // Optionally, wait for the first result to be visible
  const firstResult = page.locator('div.s-main-slot div[data-component-type="s-search-result"]').first();
  await expect(firstResult).toBeVisible({ timeout: 15000 });

  // 5. Validate sorting dropdown reflects selected option.
  await expect(sortDropdown).toHaveValue('price-asc-rank');

  // 6. Close browser.
  // (Playwright test runner closes browser automatically)
});
